example.code:
{
  "artefact_id": "design-jwt-refresh",
  "owner": "Ruslan Faion <ruslan@faion.net>",
  "version": "1.0.0",
  "last_reviewed": "2026-05-23",
  "feature": "jwt-refresh",
  "status": "Accepted",
  "spec_ref": ".aidocs/features/in-progress/jwt-refresh/spec.md",
  "decisions": [
    {
      "id": "AD-2",
      "chosen": "HS256 with 15-min access TTL, 7-day refresh TTL, rotation on use",
      "rejected": ["RS256 (overkill for monolith)", "no rotation (replay risk)"],
      "rationale": "HS256 simpler key management; rotation mitigates token-theft window.",
      "satisfies": ["FR-3", "NFR-2"]
    }
  ],
  "file_table": [
    {"action": "CREATE", "path": "apps/auth/views/refresh.py", "scope": "POST /auth/refresh view"},
    {"action": "MODIFY", "path": "apps/auth/urls.py", "scope": "Wire new URL"}
  ],
  "fr_coverage": {"FR-3": ["AD-2"]}
}
